// Publications.jsx
import React from 'react';
import PublicationCard from '../components/PublicationCard';
import publicationsData from '../assets/publications.json';

const Publications = () => {
  const journalArticles = publicationsData.filter((publication) => publication.type === 'journal');
  const conferencePresentations = publicationsData.filter((publication) => publication.type === 'conference');
  const mediaHighlights = publicationsData.filter((publication) => publication.type === 'media');

  return (
    <div style={{ marginTop: '90px' }}>
      <div style={{ paddingTop: '20px', paddingLeft: '20px' }}>
        <h2 className="year-heading">Journal Articles</h2>
        {journalArticles.map((publication, index) => (
          <PublicationCard key={index} {...publication} />
        ))}
        <h2 className="year-heading" >Conference Presentations</h2>
        {conferencePresentations.map((publication, index) => (
          <PublicationCard key={index} {...publication} />
        ))}
        <h2 className="year-heading">Media Highlights</h2>
        {mediaHighlights.map((publication, index) => (
          <PublicationCard key={index} {...publication} />
        ))}
      </div>
    </div>
  );
};

export default Publications;
